class Stack<T> {
    private var items: [T] = []

    func push(_ item: T) {
        items.append(item)
    }

    func pop() -> T? {
        return items.isEmpty ? nil : items.removeLast()
    }

    func peek() -> T? {
        return items.last
    }

    var count: Int {
        return items.count
    }

    var isEmpty: Bool {
        return items.isEmpty
    }
}

