class Controller {
    var title = "Main"

    func performAction() {
        let closure = { [weak self] in
            guard let self = self else { return }
            print("Action in \(self.title)")
        }
        closure()
    }
}

class Circle: Shape {
    let radius: Double

    init(radius: Double) {
        self.radius = radius
    }

    func area() -> Double {
        return Double.pi * radius * radius
    }

    func perimeter() -> Double {
        return 2 * Double.pi * radius
    }
}

class Triangle: Shape {
    let base: Double
    let height: Double
    let sideA: Double
    let sideB: Double

    init(base: Double, height: Double, sideA: Double, sideB: Double) {
        self.base = base
        self.height = height
        self.sideA = sideA
        self.sideB = sideB
    }

    func area() -> Double {
        return 0.5 * base * height
    }

    func perimeter() -> Double {
        return base + sideA + sideB
    }
}

class Vehicle {
    let type: VehicleType
    var speed: Double

    init(type: VehicleType, speed: Double = 0.0) {
        self.type = type
        self.speed = speed
    }

    func accelerate(by amount: Double) {
        speed += amount
    }

    func brake(by amount: Double) {
        speed = max(0, speed - amount)
    }

    func getInfo() -> String {
        return "\(type.description()) traveling at \(speed) km/h"
    }
}

class Car: Vehicle {
    let numberOfDoors: Int

    init(numberOfDoors: Int, speed: Double = 0.0) {
        self.numberOfDoors = numberOfDoors
        super.init(type: .car, speed: speed)
    }

    override func getInfo() -> String {
        return "\(numberOfDoors)-door car traveling at \(speed) km/h"
    }
}

